class DynamicWeightSystem:
    def __init__(self, base_events):
        """
        动态权重系统

        Args:
            base_events: 基础事件配置 [{"id": str, "weight": float}]
        """
        self.base_events = {e["id"]: e["weight"] for e in base_events}
        self.player_states = {}

    def get_player_state(self, player_id):
        """获取或创建玩家状态"""
        if player_id not in self.player_states:
            self.player_states[player_id] = {
                "rare_streak": 0,
                "last_rare_time": None,
                "total_rolls": 0
            }
        return self.player_states[player_id]

    def get_dynamic_weights(self, player_id):
        """获取动态权重"""
        state = self.get_player_state(player_id)
        current_time = time.time()

        weights = self.base_events.copy()

        # 稀有事件连续未获得，提升权重
        if state["rare_streak"] > 5:
            for event_id in weights:
                if event_id in ["rare", "legendary"]:
                    weights[event_id] *= (1 + state["rare_streak"] * 0.1)

        # 近期获得稀有奖励后，降低稀有事件权重
        if state["last_rare_time"]:
            time_since_rare = current_time - state["last_rare_time"]
            if time_since_rare < 3600:  # 1小时内
                for event_id in weights:
                    if event_id in ["rare", "legendary"]:
                        weights[event_id] *= 0.5

        return weights

