interface WeightedEvent {
  id: string;
  weight: number;
  [key: string]: any;
}

class WeightedRandom {
  static choose<T extends WeightedEvent>(
    events: T[], 
    weightKey: string = 'weight'
  ): T | null {
    const totalWeight = events.reduce((sum, e) => sum + e[weightKey], 0);
    const roll = Math.random() * totalWeight;

    let cumulative = 0;
    for (const event of events) {
      cumulative += event[weightKey];
      if (roll < cumulative) {
        return event;
      }
    }

    return events[events.length - 1];
  }
}

class PseudoRandom {
  private targetProb: number;
  private prdN: number;
  private currentProb: number;
  private streak: number;

  constructor(targetProb: number, prdN: number = 6) {
    this.targetProb = targetProb;
    this.prdN = prdN;
    this.currentProb = targetProb;
    this.streak = 0;
  }

  roll(): boolean {
    this.streak++;

    if (Math.random() < this.currentProb) {
      this.reset();
      return true;
    }

    this.currentProb += (1 - this.targetProb) / this.prdN;

    if (this.currentProb >= 1.0) {
      this.reset();
      return true;
    }

    return false;
  }

  reset(): void {
    this.currentProb = this.targetProb;
    this.streak = 0;
  }

  getCurrentProb(): number {
    return this.currentProb;
  }
}
